import{_ as s,o as t,c as a,ag as i}from"./chunks/framework.BqfgOMAh.js";const u=JSON.parse('{"title":"NexusFlow Skill","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/agent-skill.md","filePath":"en/guide/agent-skill.md"}'),l={name:"en/guide/agent-skill.md"};function n(o,e,r,h,p,d){return t(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="nexusflow-skill" tabindex="-1">NexusFlow Skill <a class="header-anchor" href="#nexusflow-skill" aria-label="Permalink to &quot;NexusFlow Skill&quot;">​</a></h1><p>NexusFlow Skill is the separately published instruction package that helps Cursor, Claude Code, and other skills.sh / AGENTS-compatible tools use the MCP server exposed by the NexusFlow desktop app more reliably.</p><p>Repository: <a href="https://github.com/maxzhao/nexusflow-skill" target="_blank" rel="noreferrer">https://github.com/maxzhao/nexusflow-skill</a></p><p>Install:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> skills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> maxzhao/nexusflow-skill</span></span></code></pre></div><p>It is not part of the NexusFlow desktop app, and it is not a plugin for connecting external Skills into NexusFlow. Its purpose is to <strong>teach external IDEs and agents how to use NexusFlow MCP tools safely</strong>.</p><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><p>Before installing or using NexusFlow Skill, make sure the NexusFlow runtime is ready:</p><ol><li>The NexusFlow desktop app is installed and running.</li><li>MCP mode is enabled in NexusFlow.</li><li>Your IDE or MCP client is connected to the NexusFlow MCP endpoint.</li><li>For UE operations, Unreal Engine is open and the NexusFlow UE plugin is installed and connected.</li></ol><p>If this setup is not ready yet, start with <a href="./mcp">Use NexusFlow from IDEs / Agents</a>.</p><h2 id="why-it-exists" tabindex="-1">Why It Exists <a class="header-anchor" href="#why-it-exists" aria-label="Permalink to &quot;Why It Exists&quot;">​</a></h2><p>When an external agent sees MCP tools directly, it may not know that it should:</p><ul><li>Check whether NexusFlow is connected to UE first.</li><li>Inspect the current UE context instead of guessing asset or Blueprint state.</li><li>Search and load a NexusFlow Skill guide before executing actions.</li><li>Load knowledge topics only when needed.</li><li>Treat direct Python execution as a confirmed last resort.</li></ul><p>NexusFlow Skill packages these rules as installable agent instructions so agents can operate UE with a safer and more stable workflow.</p><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h2><p>In a skills.sh-compatible environment, run:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> skills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> maxzhao/nexusflow-skill</span></span></code></pre></div><p>If GitHub access is unstable in your network, configure proxy settings for Git / npm. Example:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ALL_PROXY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">socks5://127.0.0.1:10808</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">HTTPS_PROXY=http://127.0.0.1:10808 </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">HTTP_PROXY=http://127.0.0.1:10808 </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">npx </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">skills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> maxzhao/nexusflow-skill</span></span></code></pre></div><h2 id="entrypoints" tabindex="-1">Entrypoints <a class="header-anchor" href="#entrypoints" aria-label="Permalink to &quot;Entrypoints&quot;">​</a></h2><p>After installation, the Skill repository contains entrypoints for different agents:</p><table tabindex="0"><thead><tr><th>File</th><th>Environment</th></tr></thead><tbody><tr><td><code>SKILL.md</code></td><td>Universal Skill entrypoint</td></tr><tr><td><code>AGENTS.md</code></td><td>Agents or IDEs that read AGENTS instructions</td></tr><tr><td><code>CLAUDE.md</code></td><td>Claude Code</td></tr><tr><td><code>.cursor/rules/nexusflow.mdc</code></td><td>Cursor</td></tr><tr><td><code>references/mcp-tools.md</code></td><td>Detailed MCP tool reference</td></tr></tbody></table><p>In most cases, you only need to install it through skills.sh; the target tool reads the matching file.</p><h2 id="agent-workflow" tabindex="-1">Agent Workflow <a class="header-anchor" href="#agent-workflow" aria-label="Permalink to &quot;Agent Workflow&quot;">​</a></h2><p>After installation, agents should prefer this progressive workflow:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>get_connection_status</span></span>
<span class="line"><span>  -&gt; get_ue_context</span></span>
<span class="line"><span>  -&gt; search_skills</span></span>
<span class="line"><span>  -&gt; load_skill</span></span>
<span class="line"><span>  -&gt; [load_knowledge]</span></span>
<span class="line"><span>  -&gt; execute_action</span></span></code></pre></div><p>Core rules:</p><ul><li>The live tool list and schemas shown by the MCP client are the source of truth.</li><li>Call <code>get_connection_status</code> before any UE or Blueprint operation.</li><li>After a successful connection check, call <code>get_ue_context</code> instead of guessing editor state.</li><li>Prefer searching and loading NexusFlow Skills over direct Python execution.</li><li>Do not repeatedly load the same Skill, knowledge topic, or template in one conversation.</li><li>Verify write operations after execution.</li><li>Stop immediately on <code>USER_CANCELLED</code>.</li></ul><h2 id="who-should-use-this" tabindex="-1">Who Should Use This <a class="header-anchor" href="#who-should-use-this" aria-label="Permalink to &quot;Who Should Use This&quot;">​</a></h2><ul><li>Developers who want AI in Cursor to operate UE Blueprints.</li><li>Claude Code users who want to use the NexusFlow MCP toolchain.</li><li>Teams integrating NexusFlow as an Unreal Engine automation gateway for custom agents.</li></ul><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="./mcp">Use NexusFlow from IDEs / Agents</a>: learn the MCP connection requirements and available tools.</li><li><a href="./blueprint-operations">Blueprint Operations</a>: learn the built-in Blueprint capabilities.</li></ul>`,32)])])}const k=s(l,[["render",n]]);export{u as __pageData,k as default};
